sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.process-section{

    padding:80px 30px;
    background:linear-gradient(135deg,#f5f7fa,#eef3f8);
    text-align:center;

}

.process-section h2{

    font-size:46px;
    color:#0F4C81;
    margin-bottom:15px;
    font-weight:700;

}

.section-subtitle{

    color:#666;
    font-size:18px;
    max-width:700px;
    margin:0 auto 60px auto;
    line-height:1.8;

}

.process-container{

    display:flex;
    justify-content:center;
    gap:35px;
    flex-wrap:wrap;

}

.process-card{

    position:relative;
    overflow:hidden;
    width:260px;
    background:#ffffff;
    border-radius:18px;
    padding:40px 30px;
    text-align:center;
    box-shadow:0 10px 25px rgba(15,76,129,.10);
    border-top:6px solid #0F4C81;
    transition:all .4s ease;

}

.process-card::before{

    content:"";
    position:absolute;
    top:0;
    left:-120%;
    width:100%;
    height:100%;
    background:linear-gradient(
        90deg,
        transparent,
        rgba(255,255,255,.45),
        transparent
    );
    transition:.8s;

}

.process-card:hover::before{

    left:120%;

}

.process-card:hover{

    transform:translateY(-12px) scale(1.04);
    box-shadow:0 18px 35px rgba(15,76,129,.18);

}

.step-number{

    width:85px;
    height:85px;
    margin:0 auto 25px;
    display:flex;
    align-items:center;
    justify-content:center;
    background:linear-gradient(135deg,#D4A017,#F2C94C);
    color:#ffffff;
    border-radius:50%;
    font-size:34px;
    font-weight:bold;
    box-shadow:0 8px 18px rgba(212,160,23,.30);
    transition:.4s;

}

.process-card:hover .step-number{

    transform:rotate(15deg) scale(1.12);

}

.process-card h3{

    color:#0F4C81;
    font-size:24px;
    font-weight:700;
    margin-bottom:18px;

}

.process-card p{

    color:#666;
    font-size:15px;
    line-height:1.8;
    min-height:70px;

}

@media(max-width:992px){

    .process-container{

        gap:25px;

    }

    .process-card{

        width:300px;

    }

}

@media(max-width:768px){

    .process-section{

        padding:50px 20px;

    }

    .process-section h2{

        font-size:34px;

    }

    .process-container{

        flex-direction:column;
        align-items:center;

    }

    .process-card{

        width:100%;
        max-width:360px;

    }

}
